      <div className='relative z-10 max-w-2xl'>
        <div className='type-label mb-6' style={{ color: 'rgba(255,255,255,0.35)' }}>
          {content.eyebrow}
        </div>
        <h1
          style={{
            fontFamily: 'var(--font-display)',
            fontSize: 'clamp(2.5rem, 7vw, 6rem)',
            fontWeight: 300,
            lineHeight: 1.02,
            color: '#EDE8E0',
            marginBottom: '1.5rem',
          }}
