          {content.title}
        </h1>
        <p
          style={{
            fontFamily: 'var(--font-body)',
            fontSize: '1.05rem',
            fontWeight: 300,
            color: 'rgba(255,255,255,0.55)',
            lineHeight: 1.85,
          }}
        >
          {content.body}
        </p>
      </div>
    </div>
