  try {
    await saveLookbookEntry(editorial, locale);
    revalidateLocalizedPath('/lookbook');
    return NextResponse.json({ ok: true, entry: editorial, locale });
  } catch {
    return NextResponse.json({ error: 'Failed to save lookbook entry' }, { status: 500 });
  }
}

