export const dynamic = 'force-dynamic';

function parseFilterList(searchParams: URLSearchParams, key: string): string[] {
  const seen = new Set<string>();
  const result: string[] = [];
  for (const raw of searchParams.getAll(key)) {
    for (const item of raw.split(',')) {
      const normalized = item.trim();
      if (!normalized || seen.has(normalized)) continue;
      seen.add(normalized);
      result.push(normalized);
    }
  }
  return result;
}

function productMatchesThemes(product: { lore?: string; name: string }, themes: string[]): boolean {
  if (themes.length === 0) return true;
  const lore = product.lore?.toLowerCase() ?? '';
  const name = product.name.toLowerCase();
  return themes.some((theme) => {
    const query = theme.toLowerCase();
    return lore.includes(query) || name.includes(query);
  });
}

export async function GET(req: NextRequest) {
  const ip = getClientIp(req);
  const { allowed, retryAfterSec } = checkRateLimit(`products-api:${ip}`, 60, 60_000);
  if (!allowed) {
    return NextResponse.json(
      { error: 'Too many requests. Please slow down.' },
      { status: 429, headers: { 'Retry-After': String(retryAfterSec) } },
    );
  }
  const { searchParams } = req.nextUrl;
  const collectionSlug = searchParams.get('collection') ?? undefined;
  const categoryName = searchParams.get('category') ?? undefined;
  const categoryNames = [
    ...parseFilterList(searchParams, 'categories'),
    ...(categoryName ? [categoryName] : []),
  ];
  const themeNames = parseFilterList(searchParams, 'themes');
  const search = searchParams.get('q') ?? undefined;
  const limit = Math.min(parseInt(searchParams.get('limit') ?? '100', 10), 200);
  const skip = parseInt(searchParams.get('skip') ?? '0', 10);
  const ids = searchParams.get('ids')?.split(',').map((s) => s.trim()).filter(Boolean);
  const newOnly = searchParams.get('new') === '1';
  const locale = normalizeLocale(searchParams.get('locale') ?? req.headers.get('x-ecom-locale'));
  const sort = searchParams.get('sort') ?? undefined;
  const priceMinRaw = searchParams.get('priceMin');
  const priceMaxRaw = searchParams.get('priceMax');
  const priceMin = priceMinRaw != null ? parseFloat(priceMinRaw) : undefined;
  const priceMax = priceMaxRaw != null ? parseFloat(priceMaxRaw) : undefined;

  const { products, total } = await getMentiosProducts({
    limit, skip, collectionSlug, categoryName, categoryNames, themeNames, search, ids, newOnly, locale, sort, priceMin, priceMax,
  });

  // Fall back to static demo products when DB is not configured or empty.
  if (products.length === 0) {
    let staticProducts = (collectionSlug
      ? PRODUCTS.filter((p) => p.collectionSlug === collectionSlug)
      : PRODUCTS
    ).filter((p) => !p.isSoldOut);

    if (categoryNames.length > 0) {
      const selected = new Set(categoryNames);
      staticProducts = staticProducts.filter((p) => selected.has(p.category));
    }

    if (themeNames.length > 0) {
      staticProducts = staticProducts.filter((p) => productMatchesThemes(p, themeNames));
    }

    if (search) {
      const q = search.toLowerCase();
      staticProducts = staticProducts.filter(
        (p) =>
          p.name.toLowerCase().includes(q) ||
          p.category.toLowerCase().includes(q) ||
          p.description.toLowerCase().includes(q),
      );
    }

    if (ids && ids.length > 0) {
      const requested = new Set(ids);
      staticProducts = staticProducts.filter((p) => requested.has(p.id));
    }

    if (priceMin != null) staticProducts = staticProducts.filter((p) => p.price >= priceMin);
    if (priceMax != null) staticProducts = staticProducts.filter((p) => p.price < priceMax);

    if (sort === 'price-asc') staticProducts = [...staticProducts].sort((a, b) => a.price - b.price);
    else if (sort === 'price-desc') staticProducts = [...staticProducts].sort((a, b) => b.price - a.price);

    return NextResponse.json({
      products: staticProducts.slice(skip, skip + limit),
      total: staticProducts.length,
      source: 'static',
    });
  }

  return NextResponse.json({ products, total, source: 'mentios' });
}

import { NextRequest, NextResponse } from 'next/server';
import {
  applyInpostTrackingEvent,
  parseInpostTrackingEvent,
  verifyInpostWebhookSignature,
} from '@/lib/inpost';

export async function POST(req: NextRequest): Promise<NextResponse> {
  const rawBody = await req.text();
  const signatureHeader = req.headers.get('x-inpost-signature');

  if (!verifyInpostWebhookSignature(rawBody, signatureHeader)) {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
  }

  let payload: unknown;
  try {
    payload = JSON.parse(rawBody);
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const event = parseInpostTrackingEvent(payload);
  if (!event) {
    return NextResponse.json({ error: 'Invalid tracking event' }, { status: 400 });
  }

  const result = await applyInpostTrackingEvent(event);
  return NextResponse.json({
    ok: true,
    matched: result.matched,
    modified: result.modified,
    duplicate: result.duplicate,
    stale: result.stale,
    orderStatus: result.orderStatus,
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/mongodb';
import { ORDERS_COLLECTION, type Order, serializeOrder } from '@/lib/orders';
import { verifyPayUWebhook } from '@/lib/payu';
import { sendOrderConfirmation } from '@/lib/email';
import { fulfillInpostOrder } from '@/lib/inpost';

interface PayUNotification {
  order?: {
    orderId?: string;
    extOrderId?: string;
    status?: string;
  };
}

// Maps PayU order statuses to our internal order statuses.
function mapStatus(payuStatus: string): Order['status'] | null {
  switch (payuStatus) {
    case 'COMPLETED':
      return 'processing';
    case 'CANCELED':
    case 'REJECTED':
      return 'cancelled';
    case 'PENDING':
    case 'WAITING_FOR_CONFIRMATION':
      return 'pending_payment';
    default:
      return null;
  }
}

export async function POST(req: NextRequest): Promise<NextResponse> {
  const rawBody = await req.text();
  const signatureHeader = req.headers.get('OpenPayU-Signature');

  // In production, always verify the signature. In development (no PAYU_SECOND_KEY
  // configured) we allow unsigned notifications so local testing works.
  const isDev = process.env.NODE_ENV !== 'production';
  if (!isDev && !verifyPayUWebhook(rawBody, signatureHeader)) {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
  }

  let notification: PayUNotification;
  try {
    notification = JSON.parse(rawBody) as PayUNotification;
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const payuOrderId = notification.order?.orderId;
  const payuStatus = notification.order?.status ?? '';
  // extOrderId is our orderId (e.g. ARC-2026-XXXXXXXX)
  const extOrderId = notification.order?.extOrderId;

  if (!payuStatus) {
    return NextResponse.json({ ok: true }); // ignore non-order notifications
  }

  const newStatus = mapStatus(payuStatus);
  if (!newStatus) {
    return NextResponse.json({ ok: true }); // unknown status — acknowledge but don't update
  }

  const db = await getDb();
  const filter = payuOrderId
    ? { payuOrderId }
    : extOrderId
      ? { orderId: extOrderId }
      : null;

  if (!filter) {
    return NextResponse.json({ ok: true });
  }

  const updatedDoc = await db
    .collection(ORDERS_COLLECTION)
    .findOneAndUpdate(filter, { $set: { status: newStatus } }, { returnDocument: 'after' });

  // Send confirmation email only once, when the payment is confirmed by the bank.
  if (newStatus === 'processing' && updatedDoc) {
    const order = serializeOrder(updatedDoc);
    let emailOrder = order;
    try {
      const shipment = await fulfillInpostOrder(order);
      if (shipment) emailOrder = { ...order, inpostShipment: shipment };
    } catch (err: unknown) {
      console.error('Failed to create InPost shipment', err);
    }
    void sendOrderConfirmation(emailOrder).catch((err: unknown) => {
      console.error('Failed to send BLIK order confirmation email', err);
    });
  }

  return NextResponse.json({ ok: true });
}

import { NextRequest, NextResponse } from 'next/server';
import { getEcomAuthDb } from '@/lib/mongodb';
import { getSession } from '@/lib/auth';
import { ensureAppIndexes } from '@/lib/db-indexes';
import type { WishlistItem } from '@/context/WishlistContext';

const MAX_WISHLIST_ITEMS = 200;

function sanitizeItem(raw: unknown): WishlistItem | null {
  if (typeof raw !== 'object' || raw === null || Array.isArray(raw)) return null;
  const item = raw as Record<string, unknown>;
  const productId = typeof item['productId'] === 'string' ? item['productId'].trim() : '';
  const slug = typeof item['slug'] === 'string' ? item['slug'].trim() : '';
  const name = typeof item['name'] === 'string' ? item['name'].trim() : '';
  if (!productId || !slug || !name) return null;
  return {
    productId,
    slug,
    name,
    category: typeof item['category'] === 'string' ? item['category'].trim() : '',
    price: typeof item['price'] === 'number' && item['price'] >= 0 ? item['price'] : 0,
    priceDisplay: typeof item['priceDisplay'] === 'string' ? item['priceDisplay'].trim() : '',
    gradient: typeof item['gradient'] === 'string' ? item['gradient'].trim() : '',
    imageUrl: typeof item['imageUrl'] === 'string' ? item['imageUrl'].trim() : undefined,
  } as WishlistItem;
}

// GET — return the logged-in user's saved wishlist
export async function GET(): Promise<NextResponse> {
  void ensureAppIndexes();
  const user = await getSession();
  if (!user) return NextResponse.json({ items: [] });

  const db = await getEcomAuthDb();
  const doc = await db.collection('ecom_wishlists').findOne({ userId: user.id });
  return NextResponse.json({ items: (doc?.items as WishlistItem[]) ?? [] });
}

// POST — replace the wishlist for the logged-in user
export async function POST(req: NextRequest): Promise<NextResponse> {
  const user = await getSession();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  if (typeof body !== 'object' || body === null || !('items' in body)) {
    return NextResponse.json({ error: 'items must be an array' }, { status: 400 });
  }

  const rawItems = (body as Record<string, unknown>)['items'];
  if (!Array.isArray(rawItems)) {
    return NextResponse.json({ error: 'items must be an array' }, { status: 400 });
  }

  if (rawItems.length > MAX_WISHLIST_ITEMS) {
    return NextResponse.json(
      { error: `Wishlist cannot exceed ${MAX_WISHLIST_ITEMS} items` },
      { status: 400 },
    );
  }

  const items: WishlistItem[] = [];
  for (const raw of rawItems) {
    const item = sanitizeItem(raw);
    if (!item) return NextResponse.json({ error: 'Invalid wishlist item' }, { status: 400 });
    items.push(item);
  }

  const db = await getEcomAuthDb();
  await db.collection('ecom_wishlists').updateOne(
    { userId: user.id },
    { $set: { userId: user.id, items, updatedAt: new Date() } },
    { upsert: true },
  );

  return NextResponse.json({ ok: true });
}

