import { notFound } from 'next/navigation';
import type { Metadata } from 'next';
import type { JSX } from 'react';
import { COLLECTIONS, getProductsByCollection } from '@/data/products';
import { getMentiosProducts } from '@/lib/mentios';
import { CollectionPageClient } from './CollectionPageClient';
import { getProductsContent } from '@/lib/cms';
import { getRequestLocale } from '@/lib/request-locale';

type Props = { params: Promise<{ slug: string }> };

export const revalidate = 120;

const PAGE_SIZE = 24;

function collectionLabel(slug: string, fallback: string, locale: string): string {
  if (locale !== 'pl') return fallback;
  return ({
    womenswear: 'Anime',
    menswear: 'Gaming',
    accessories: 'Film i TV',
    objects: 'Wszystkie produkty',
  } as Record<string, string>)[slug] ?? fallback;
}

export async function generateStaticParams() {
  return COLLECTIONS.map((c) => ({ slug: c.slug }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const locale = await getRequestLocale();
  const collection = COLLECTIONS.find((c) => c.slug === slug);
  if (!collection) return {};
  const title = `${collectionLabel(slug, collection.label, locale)} - ARCANA`;
  const description = `Shop the ${collection.label} collection — ARCANA`;
  return {
    title,
    description,
    openGraph: { type: 'website', title, description },
    twitter: { card: 'summary', title, description },
  };
}

export default async function CollectionPage({ params }: Props): Promise<JSX.Element> {
  const { slug } = await params;
  const locale = await getRequestLocale();
  const collection = COLLECTIONS.find((c) => c.slug === slug);
  if (!collection) notFound();

  // Fetch first page from DB and CMS content in parallel.
  const [{ products: dbProducts, total: dbTotal }, content] = await Promise.all([
    getMentiosProducts({ limit: PAGE_SIZE, collectionSlug: slug, locale }),
    getProductsContent(locale),
  ]);

  const isLive = dbProducts.length > 0;
  const products = isLive ? dbProducts : getProductsByCollection(slug);
  const total = isLive ? dbTotal : collection.count;
  const source: 'mentios' | 'static' = isLive ? 'mentios' : 'static';

  return (
    <CollectionPageClient
      collection={{ ...collection, label: collectionLabel(slug, collection.label, locale), count: total }}
      products={products}
      total={total}
      source={source}
      content={content}
    />
  );
}

'use client';

import { useState, type JSX } from 'react';
import type { ContactContent } from '@/data/contactContent';
import { SiteNav } from '@/components/SiteNav';
import { SiteFooter } from '@/components/SiteFooter';
import { useToast } from '@/context/ToastContext';
import { useLocalizedHref } from '@/context/LocaleContext';

export function ContactPageClient({ content }: { content: ContactContent }): JSX.Element {
  const { toast } = useToast();
  const localizedHref = useLocalizedHref();
  const [sent, setSent] = useState(false);
  const [form, setForm] = useState({
    name: '',
    email: '',
    subject: content.form.subjects[0] ?? '',
    message: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSent(true);
    toast({ type: 'success', title: content.success.toastTitle, message: content.success.toastMessage });
  };

  return (
    <>
      <SiteNav />
      <main style={{ paddingTop: 'var(--nav-h)', minHeight: '100vh' }}>

        {/* ── Hero ─────────────────────────────────────────────────── */}
        <div
          className="relative overflow-hidden px-8 md:px-16 py-20 md:py-28"
          style={{
            background: 'linear-gradient(160deg, #1a1208 0%, #0d0d0b 60%, #0a0908 100%)',
          }}
        >
          {/* Outlined watermark */}
          <div
            className="absolute inset-0 flex items-center justify-end pr-8 md:pr-16 pointer-events-none select-none"
            aria-hidden="true"
          >
            <span
              style={{
                fontFamily: 'var(--font-display)',
                fontSize: 'clamp(5rem, 16vw, 16rem)',
                fontWeight: 300,
                color: 'transparent',
                WebkitTextStroke: '1px rgba(255,255,255,0.05)',
                lineHeight: 1,
                letterSpacing: '-0.04em',
              }}
            >
              {content.hero.watermark}
            </span>
          </div>

          <div className="relative z-10 max-w-screen-2xl mx-auto">
            <div
              className="type-label mb-4"
              style={{ color: 'rgba(180,140,80,0.8)', letterSpacing: '0.14em' }}
            >
              {content.hero.eyebrow}
            </div>
            <h1
              style={{
                fontFamily: 'var(--font-display)',
                fontSize: 'clamp(2.5rem, 7vw, 6rem)',
                fontWeight: 300,
