});

const themeInitScript = `
(() => {
  try {
    const storedTheme = localStorage.getItem('arcana-theme');
    const theme = storedTheme === 'daily' ? 'daily' : 'nightly';
    const root = document.documentElement;
    root.classList.remove('daily', 'nightly', 'dark');
    root.classList.add(theme);
    if (theme === 'nightly') root.classList.add('dark');
    root.dataset.theme = theme;
  } catch {
    document.documentElement.dataset.theme = 'nightly';
  }
})();
`;

const siteUrl =
  process.env.NEXT_PUBLIC_ECOM_URL ??
  (process.env.VERCEL_PROJECT_PRODUCTION_URL
    ? `https://${process.env.VERCEL_PROJECT_PRODUCTION_URL}`
    : 'http://localhost:3001');

export async function generateMetadata(): Promise<Metadata> {
  const locale = await getRequestLocale();
  const isPl = locale === 'pl';

  const title = isPl
    ? 'ARCANA - Anime, gaming i filmowe kolekcjonalia'
    : 'ARCANA - Anime, Gaming, and Film Collectibles';
  const description = isPl
    ? 'Breloki, piny i biżuteria z ulubionych uniwersów. Kolekcjonalia anime, gamingowe i filmowe - licencjonowane i starannie wybrane.'
    : 'Keychains, pins and jewellery from the universes you love. Anime, gaming and film collectibles - officially licensed, obsessively curated.';

  return {
    title,
    description,
    metadataBase: new URL(siteUrl),
    openGraph: {
      type: 'website',
      siteName: 'ARCANA',
      title,
      description,
      locale: isPl ? 'pl_PL' : 'en_GB',
    },
    twitter: {
      card: 'summary_large_image',
      title,
      description,
    },
    robots: {
      index: true,
      follow: true,
      googleBot: { index: true, follow: true },
    },
  };
}

export default async function RootLayout({ children }: { children: ReactNode }): Promise<JSX.Element> {
  const { locale, pathname, search } = await getRequestLocaleState();
  const [siteContent, availableLocales] = await Promise.all([
    getSiteContent(locale),
    getMentiosCatalogLocales(),
  ]);

  return (
    <html
      lang={locale}
      suppressHydrationWarning
      data-theme="nightly"
      className={`nightly dark ${exo2.variable} ${barlow.variable} ${ibmPlexMono.variable}`}
    >
      <head>
        <script dangerouslySetInnerHTML={{ __html: themeInitScript }} />
      </head>
      <body>
        <LocaleProvider locale={locale} pathname={pathname} search={search} availableLocales={availableLocales}>
          <SiteContentProvider content={siteContent}>
            <ToastProvider>
              <AuthProvider>
              <WishlistProvider>
                <RecentlyViewedProvider>
                <QuickViewProvider>
                <CartProvider>
                  {children}
                  <CartDrawer />
                  <ToastContainer />
                  <BackToTop />
                  <QuickViewModal />
                  <CookieConsent />
                </CartProvider>
                </QuickViewProvider>
                </RecentlyViewedProvider>
              </WishlistProvider>
              </AuthProvider>
            </ToastProvider>
          </SiteContentProvider>
        </LocaleProvider>
      </body>
    </html>
  );
}

