export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const locale = await getRequestLocale();
  const story = await getStoryBySlug(slug, locale);
  if (!story) return {};
  const content = await getStoriesPageContent(locale);
  const title = `${story.title} - ${content.detail.issueLabelPrefix}`;
  const description = story.excerpt.slice(0, 155);
  return {
    title,
    description,
    openGraph: {
      type: 'article',
      title,
      description,
      publishedTime: story.date,
      tags: story.tags,
    },
    twitter: {
      card: 'summary_large_image',
      title,
      description,
    },
  };
}

function readTimeLabel(value: string, locale: string): string {
  return locale === 'pl' ? `${value} czytania` : `${value} read`;
