          if (cardIndex !== index) return card;
          const exists = card.selectorValues.includes(value);
          return {
            ...card,
            selectorValues: exists
              ? card.selectorValues.filter((item) => item !== value)
              : [...card.selectorValues, value],
          };
        }),
      },
    }));
