                    <input
                      id="si-password"
                      type={siShowPw ? 'text' : 'password'}
                      autoComplete="current-password"
                      value={siPassword}
                      onChange={(e) => setSiPassword(e.target.value)}
                      required
                      style={{ ...inputStyle, paddingRight: '2.75rem' }}
                      onFocus={(e) => (e.currentTarget.style.borderColor = 'rgba(var(--accent-rgb),0.5)')}
