function getCardHref(card: HomeCategoriesContent['cards'][number]): string {
  const values = card.selectorValues.map((value) => value.trim()).filter(Boolean);
  if (card.selectorType === 'all') return '/products';
  if (card.selectorType === 'category' && values.length > 0) {
    const params = new URLSearchParams();
    params.set('categories', values.join(','));
    return `/products?${params.toString()}`;
  }
  if (card.selectorType === 'theme' && values.length > 0) {
    const params = new URLSearchParams();
    params.set('themes', values.join(','));
    return `/products?${params.toString()}`;
  }
  return card.href || '/products';
}

export function CategoriesGrid({
  counts = {},
  content = HOME_CONTENT_DEFAULTS.categories,
}: {
  counts?: Record<string, number>;
  content?: HomeCategoriesContent;
}): JSX.Element {
  const sectionRef = useRef<HTMLElement>(null);
  const hasLiveCounts = Object.keys(counts).length > 0;
  const localizedHref = useLocalizedHref();

  useGSAP(() => {
    /* Section header reveal */
    gsap.fromTo('.cat-header',
      { opacity: 0, y: 40 },
      {
        opacity: 1, y: 0, duration: 0.9, ease: 'expo.out',
        scrollTrigger: {
          trigger: '.cat-header',
          start: 'top 88%',
          toggleActions: 'play none none none',
        },
      });

    /* Cards stagger in on scroll */
    ScrollTrigger.batch('.cat-card', {
      start: 'top 90%',
      onEnter: (batch) => {
        gsap.fromTo(batch,
          { opacity: 0, y: 60, clipPath: 'inset(0 0 30% 0)' },
          {
            opacity: 1, y: 0, clipPath: 'inset(0 0 0% 0)',
            duration: 1.0, ease: 'expo.out', stagger: 0.1,
          });
      },
    });
  }, { scope: sectionRef, dependencies: [] });

  return (
    <section ref={sectionRef} className="px-6 md:px-10 pt-20 pb-16 max-w-screen-2xl mx-auto">
      {/* Section header */}
      <div className="cat-header flex items-end justify-between mb-12" style={{ opacity: 0 }}>
        <div>
          <div className="type-label mb-3" style={{ color: 'var(--accent)' }}>
            {content.eyebrow}
          </div>
          <h2 className="type-display-lg" style={{ color: 'var(--fg)' }}>
            {content.title}
          </h2>
        </div>
        <a
          href={localizedHref(content.ctaHref)}
          className="hidden md:flex type-label items-center gap-2 hover:gap-3 transition-all duration-200"
          style={{ color: 'var(--muted-teal)' }}
        >
          {content.ctaLabel}
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round">
            <path d="M5 12h14M12 5l7 7-7 7" />
          </svg>
        </a>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4">
        {content.cards.map((cat, i) => {
          const visual = CATEGORY_VISUALS.find((item) => item.id === cat.id) ?? CATEGORY_VISUALS[i] ?? DEFAULT_VISUAL;
          const liveCount = counts[cat.id] ?? (cat.id === 'objects' ? Object.values(counts).reduce((a, b) => a + b, 0) : undefined);
          const displayCount = liveCount != null
            ? `${liveCount.toLocaleString()} items`
            : `${cat.fallbackCount.toLocaleString()}+ items`;

          return (
            <a
              key={cat.id}
              href={localizedHref(getCardHref(cat))}
              className="cat-card category-card group block"
              style={{ aspectRatio: visual.aspectRatio, opacity: 0 }}
            >
              {/* Background */}
              {cat.imageUrl.trim() ? (
                <>
                  <img
                    src={cat.imageUrl}
                    alt=""
                    className="absolute inset-0 h-full w-full object-cover transition-transform duration-700 group-hover:scale-[1.04]"
                    loading="lazy"
                  />
                  <div
                    className="cat-bg absolute inset-0"
                    style={{ background: 'linear-gradient(180deg, rgba(4,3,20,0.14) 0%, rgba(4,3,20,0.76) 100%)' }}
                  />
                </>
              ) : (
                <div className="cat-bg absolute inset-0" style={{ background: visual.gradient }} />
              )}

              {/* Dot grid */}
              <div className="absolute inset-0 dot-grid opacity-30" />

              {/* Scanlines */}
              <div
                className="absolute inset-0 pointer-events-none"
                style={{
                  background: 'repeating-linear-gradient(0deg, transparent, transparent 3px, var(--scanline-soft) 3px, var(--scanline-soft) 4px)',
                }}
              />

              {/* Corner brackets */}
              <div className="absolute top-4 left-4 w-6 h-6 z-10 transition-opacity duration-300"
                style={{ borderTop: `1.5px solid rgba(${visual.accentRgb},0.5)`, borderLeft: `1.5px solid rgba(${visual.accentRgb},0.5)` }} />
              <div className="absolute bottom-4 right-4 w-6 h-6 z-10 transition-opacity duration-300"
                style={{ borderBottom: `1.5px solid rgba(${visual.accentRgb},0.5)`, borderRight: `1.5px solid rgba(${visual.accentRgb},0.5)` }} />

              {/* Content */}
              <div className="absolute inset-0 p-5 flex flex-col justify-between z-20">
                {/* Tag */}
                <div>
                  <span
                    className="type-label inline-block"
                    style={{
                      color: visual.accent,
                      background: `rgba(${visual.accentRgb},0.1)`,
                      border: `1px solid rgba(${visual.accentRgb},0.3)`,
                      padding: '0.2rem 0.55rem',
                    }}
                  >
                    {cat.tag}
                  </span>
                </div>

                {/* Label + sublabel + count */}
                <div>
                  <h3
                    style={{
                      fontFamily: 'var(--font-display)',
                      fontSize: 'clamp(1.15rem, 2.2vw, 1.9rem)',
                      fontWeight: 800,
                      lineHeight: 1,
                      color: 'var(--on-media)',
                      marginBottom: '0.35rem',
                      letterSpacing: '-0.01em',
                    }}
                  >
                    {cat.label}
                  </h3>
                  <p className="type-label mb-2" style={{ color: `rgba(${visual.accentRgb},0.65)`, letterSpacing: '0.1em' }}>
                    {cat.sublabel}
                  </p>
                  <p className="type-label" style={{ color: `rgba(${visual.accentRgb},0.4)` }}>
                    {displayCount}
                    {hasLiveCounts && liveCount != null && (
                      <span style={{ color: visual.accent, opacity: 0.6 }}> · live</span>
                    )}
                  </p>
                </div>
              </div>
            </a>
          );
        })}
      </div>
    </section>
  );
}

