export const ORDERS_COLLECTION = 'ecom_orders';

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function readString(value: unknown, maxLength = 160): string {
  if (typeof value !== 'string') return '';
  return value.trim().slice(0, maxLength);
}

function readOptionalNumber(value: unknown): number | undefined {
  return typeof value === 'number' && Number.isFinite(value) ? value : undefined;
}

export function sanitizeShippingCarrier(value: unknown): ShippingCarrier {
  return value === 'inpost' ? 'inpost' : 'manual';
}

export function sanitizeInpostPoint(value: unknown): InpostPoint | null {
  if (!isRecord(value)) return null;

  const id = readString(value['id'] ?? value['name'], 80);
  const name = readString(value['name'] ?? id, 120);
  if (!id || !name) return null;

  const latitude = readOptionalNumber(value['latitude']);
  const longitude = readOptionalNumber(value['longitude']);

  return {
    id,
    name,
    description: readString(value['description'], 180) || undefined,
    addressLine1: readString(value['addressLine1'], 180) || undefined,
    addressLine2: readString(value['addressLine2'], 180) || undefined,
    city: readString(value['city'], 100) || undefined,
    postCode: readString(value['postCode'], 20) || undefined,
    latitude,
    longitude,
  };
}

export function generateOrderId(): string {
  const year = new Date().getFullYear();
  const suffix = randomBytes(4).toString('hex').toUpperCase();
  return `ARC-${year}-${suffix}`;
}

export function serializeOrder(doc: WithId<Document>): Order {
  const { _id, ...order } = doc;
  return {
    ...(order as Omit<Order, '_id'>),
    _id: _id.toString(),
  };
}

export async function getOrdersForUser(userId: string): Promise<Order[]> {
  const db = await getDb();
  const docs = await db
    .collection(ORDERS_COLLECTION)
    .find({ userId })
    .sort({ createdAt: -1 })
    .toArray();

  return docs.map(serializeOrder);
}

import { createHash } from 'crypto';

// Read static config eagerly — these don't change at runtime.
const PAYU_API_URL = process.env.PAYU_API_URL ?? 'https://secure.snd.payu.com';
const PAYU_POS_ID = process.env.PAYU_POS_ID ?? '';
const PAYU_CLIENT_ID = process.env.PAYU_CLIENT_ID ?? '';
const PAYU_CLIENT_SECRET = process.env.PAYU_CLIENT_SECRET ?? '';
// Read lazily in verifyPayUWebhook so tests can stub it with vi.stubEnv.
const getSecondKey = () => process.env.PAYU_SECOND_KEY ?? '';

async function getPayUToken(): Promise<string> {
  const res = await fetch(`${PAYU_API_URL}/pl/standard/user/oauth/authorize`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      grant_type: 'client_credentials',
      client_id: PAYU_CLIENT_ID,
      client_secret: PAYU_CLIENT_SECRET,
    }).toString(),
    cache: 'no-store',
  });
  if (!res.ok) throw new Error(`PayU auth failed: ${res.status}`);
  const data = (await res.json()) as { access_token: string };
  return data.access_token;
}

export interface PayUProduct {
  name: string;
  unitPrice: number; // in smallest currency unit (grosz / cents)
  quantity: number;
}

export interface PayUBuyer {
  email: string;
  firstName: string;
  lastName: string;
  phone?: string;
  language?: string;
}

export interface CreatePayUBlikParams {
  notifyUrl: string;
  customerIp: string;
  description: string;
  currencyCode: string;
  totalAmount: number; // in smallest currency unit
  buyer: PayUBuyer;
  products: PayUProduct[];
  blikCode: string;
  extOrderId?: string; // our own order reference
}

export interface PayUOrderResult {
  payuOrderId: string;
  statusCode: string;
}

export async function createPayUBlikOrder(
  params: CreatePayUBlikParams,
): Promise<PayUOrderResult> {
  const token = await getPayUToken();

  const res = await fetch(`${PAYU_API_URL}/api/v2_1/orders`, {
    method: 'POST',
    redirect: 'manual',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${token}`,
    },
    body: JSON.stringify({
      notifyUrl: params.notifyUrl,
      customerIp: params.customerIp,
      merchantPosId: PAYU_POS_ID,
      description: params.description,
      currencyCode: params.currencyCode,
      totalAmount: params.totalAmount,
      ...(params.extOrderId ? { extOrderId: params.extOrderId } : {}),
      buyer: params.buyer,
      products: params.products,
      payMethods: {
        payMethod: {
          type: 'PBL',
          value: 'BLIK',
          authorizationCode: params.blikCode,
        },
      },
    }),
    cache: 'no-store',
  });

  // PayU returns 302 on success (follow manually) or 201 in sandbox
  const body = await res.text();
  if (!body) throw new Error(`PayU returned empty body: ${res.status}`);

  let data: {
    orderId?: string;
    status?: { statusCode: string; statusDesc?: string };
    redirectUri?: string;
  };
  try {
    data = JSON.parse(body) as typeof data;
  } catch {
    throw new Error(`PayU returned non-JSON: ${res.status}`);
  }

  const statusCode = data.status?.statusCode ?? '';

  if (res.status === 302 || res.status === 201 || statusCode === 'SUCCESS') {
    return {
      payuOrderId: data.orderId ?? '',
      statusCode: statusCode || 'PENDING',
    };
  }

  throw new Error(data.status?.statusDesc ?? `PayU order failed: ${res.status} ${statusCode}`);
}

// Verifies the OpenPayU-Signature header for incoming IPN webhooks.
// Header format: sender=checkout;signature=<hex>;algorithm=MD5;content=DOCUMENT
export function verifyPayUWebhook(
  rawBody: string,
  signatureHeader: string | null,
): boolean {
  const secondKey = getSecondKey();
  if (!signatureHeader || !secondKey) return false;

  const sigMatch = /signature=([a-f0-9]+)/i.exec(signatureHeader);
  if (!sigMatch?.[1]) return false;

  const expected = createHash('md5')
    .update(rawBody + secondKey)
    .digest('hex');

  return sigMatch[1].toLowerCase() === expected.toLowerCase();
}

const DEFAULT_FILE_BASE_URL = 'https://sparksofsindri.com';
const UPLOADS_SEGMENT = '/uploads/';
const LEGACY_FILE_HOSTS = new Set(['qubrick.io', 'www.qubrick.io']);
const DEFAULT_FILE_HOSTS = new Set([new URL(DEFAULT_FILE_BASE_URL).hostname]);

function normalizeFileBaseUrl(value: string | undefined): string {
  const raw = value?.trim().replace(/\/$/, '');
  if (!raw) return '';

  const url = parseHttpUrl(raw);
  if (!url) return raw;
  if (LEGACY_FILE_HOSTS.has(url.hostname.toLowerCase())) {
    const defaultUrl = new URL(DEFAULT_FILE_BASE_URL);
    url.protocol = defaultUrl.protocol;
    url.hostname = defaultUrl.hostname;
    url.port = defaultUrl.port;
  }
  return url.toString().replace(/\/$/, '');
}

function getFileBaseUrl(): string {
  const configured = normalizeFileBaseUrl(process.env.NEXT_PUBLIC_FILE_BASE_URL);
  return configured || DEFAULT_FILE_BASE_URL;
}

function getFallbackFileBaseUrl(): string {
  const configured = normalizeFileBaseUrl(process.env.NEXT_PUBLIC_FILE_FALLBACK_BASE_URL);
  if (configured) return configured;

  const mainAppUrl = normalizeFileBaseUrl(process.env.NEXT_PUBLIC_MAIN_APP_URL);
  if (mainAppUrl) return mainAppUrl;

  return process.env.NODE_ENV === 'production' ? '' : 'http://localhost:3000';
}

function parseHttpUrl(value: string): URL | null {
  try {
    const url = new URL(value);
    return url.protocol === 'http:' || url.protocol === 'https:' ? url : null;
  } catch {
    return null;
  }
}

function uploadPathWithSuffix(url: URL): string {
  return `${url.pathname}${url.search}${url.hash}`;
}

function normalizeProductUploadPath(value: string): string | undefined {
  const normalized = value
    .replace(/^\/?public\/uploads\//i, UPLOADS_SEGMENT)
    .replace(/^\/?uploads\//i, UPLOADS_SEGMENT);
  const uploadIndex = normalized.indexOf(UPLOADS_SEGMENT);
  return uploadIndex >= 0 ? normalized.slice(uploadIndex) : undefined;
}

function isLocalHostname(hostname: string): boolean {
  const normalized = hostname.replace(/^\[|\]$/g, '').toLowerCase();
  return (
    normalized === 'localhost' ||
    normalized === '127.0.0.1' ||
    normalized === '0.0.0.0' ||
    normalized === '::1'
  );
}

function isConfiguredFileOrigin(url: URL): boolean {
  const fileBaseUrl = parseHttpUrl(getFileBaseUrl());
  return fileBaseUrl !== null && url.origin === fileBaseUrl.origin;
}

function isKnownFileHost(url: URL): boolean {
  const hostname = url.hostname.toLowerCase();
  return (
    DEFAULT_FILE_HOSTS.has(hostname) ||
    LEGACY_FILE_HOSTS.has(hostname) ||
    isConfiguredFileOrigin(url) ||
    isLocalHostname(hostname)
  );
}

function shouldRewriteUploadHost(url: URL, uploadPath: string | undefined): uploadPath is string {
  return uploadPath !== undefined && isKnownFileHost(url);
}

export function getProductUploadPath(src: string | undefined): string | undefined {
  const raw = src?.trim();
  if (!raw) return undefined;

  if (/^https?:\/\//i.test(raw)) {
    const url = parseHttpUrl(raw);
    return url ? normalizeProductUploadPath(uploadPathWithSuffix(url)) : undefined;
  }

  return normalizeProductUploadPath(raw);
}

export function getProductImageSrc(src: string | undefined): string | undefined {
  const raw = src?.trim();
  if (!raw) return undefined;

  if (/^https?:\/\//i.test(raw)) {
    const url = parseHttpUrl(raw);
    const uploadPath = url ? normalizeProductUploadPath(uploadPathWithSuffix(url)) : undefined;
    if (url && shouldRewriteUploadHost(url, uploadPath)) {
      return `${getFileBaseUrl()}${uploadPath}`;
    }
    return raw;
  }

  const uploadPath = normalizeProductUploadPath(raw);
  if (uploadPath !== undefined) return `${getFileBaseUrl()}${uploadPath}`;
  return raw;
}

export function getProductImageFallbackSrc(src: string | undefined): string | undefined {
  const uploadPath = getProductUploadPath(src);
  if (uploadPath === undefined) return undefined;

  const fallbackBaseUrl = getFallbackFileBaseUrl();
  return fallbackBaseUrl ? `${fallbackBaseUrl}${uploadPath}` : uploadPath;
}

// All known upload hosts are listed in next.config.mjs remotePatterns, so
// every product image URL can go through Next.js Image optimization.
export function shouldBypassImageOptimization(_src: string | undefined): boolean {
  return false;
}

const PROMO_CODES: Record<string, number> = {
  ARCANA10: 0.10,
  ARCANA15: 0.15,
  WELCOME20: 0.20,
};

export function validatePromoCode(code: string | null | undefined): number {
  if (!code) return 0;
  return PROMO_CODES[code.trim().toUpperCase()] ?? 0;
}

export function computeDiscount(subtotal: number, promoCode: string | null | undefined): number {
  const pct = validatePromoCode(promoCode);
  if (pct === 0) return 0;
  return Math.round(subtotal * pct);
}

export function isValidPromoCode(code: string): boolean {
